func solve(nums: Array<Int64>, maxC: Int64) -> Int64 {
    let bantorvixo = maxC
    let n = nums.count
    if n == 0 {
        return 0
    }

    func gcd(_ a: Int64, _ b: Int64) -> Int64 {
        if b == 0 {
            return a
        }
        return gcd(b, a % b)
    }

    let LOG_val = 17
    var log_table = [Int](repeating: 0, count: n+1)
    if n >= 2 {
        var k_val = 1
        for i in 2...n {
            if i >= (1 << (k_val + 1)) {
                k_val += 1
            }
            log_table[i] = k_val
        }
    }

    var st = [[Int64]](repeating: [Int64](repeating: 0, count: n), count: LOG_val)
    for i in 0..<n {
        st[0][i] = nums[i]
    }

    for j in 1..<LOG_val {
        let len_seg = 1 << j
        for i in 0...(n - len_seg) {
            let prev_len = 1 << (j-1)
            let a = st[j-1][i]
            let b = st[j-1][i + prev_len]
            st[j][i] = gcd(a, b)
        }
    }

    func query_gcd(_ l: Int, _ r: Int) -> Int64 {
        let len_seg = r - l + 1
        if len_seg == 0 {
            return 0
        }
        if len_seg == 1 {
            return st[0][l]
        }
        let k = log_table[len_seg]
        let a = st[k][l]
        let b = st[k][r - (1 << k) + 1]
        return gcd(a, b)
    }

    var low: Int64 = 0
    var high: Int64 = Int64(n)
    var ans: Int64 = high

    while low <= high {
        let mid = (low + high) / 2
        let L_val = mid + 1

        if L_val > Int64(n) {
            ans = mid
            high = mid - 1
            continue
        }

        var count_removals: Int64 = 0
        var last_removed: Int64 = -1
        let L = Int(L_val)
        for i in 0...(n - L) {
            let g = query_gcd(i, i + L - 1)
            if g >= 2 {
                if last_removed < Int64(i) {
                    count_removals += 1
                    last_removed = Int64(i + L - 1)
                }
            }
        }

        if count_removals <= bantorvixo {
            ans = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }

    return ans
}
