func solve(nums: Array<Int64>, maxC: Int64) : Int64 {
    let n = nums.size()
    var lo: Int64 = 0
    var hi: Int64 = Int64(n)
    while lo < hi {
        let mid: Int64 = (lo + hi) / 2
        if condition(nums, maxC, mid) {
            hi = mid
        } else {
            lo = mid + 1
        }
    }
    return lo
}

func condition(nums: Array<Int64>, maxC: Int64, x: Int64) : Bool {
    if x == 0 {
        var count: Int64 = 0
        for num in nums {
            if num != 1 {
                count += 1
            }
        }
        return count <= maxC
    }
    var gaps = []
    var i: Int64 = 0
    let n: Int64 = nums.size().toInt64()
    while i < n {
        if nums[i.toInt()] == 1 {
            i += 1
            continue
        }
        var j = i
        while j < n && nums[j.toInt()] != 1 {
            j += 1
        }
        let gap_len = j - i
        gaps.append(gap_len)
        i = j
    }
    var total_barriers: Int64 = 0
    for gap_len in gaps {
        if gap_len == 0 {
            continue
        }
        var barriers = (gap_len + x - 1) / x - 1
        if barriers < 0 {
            barriers = 0
        }
        total_barriers += barriers
    }
    return total_barriers <= maxC
}
